// Hermes-safe plural selection — baked table, NO Intl.PluralRules.
const PLURAL: Record<Locale, (n: number) => keyof Forms> = {
  en: (n) => (n === 1 ? "one" : "other"),
  es: (n) => (n === 1 ? "one" : "other"),
};

